  ('pukao-6e11b43e-moex-00149', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-113-4dccc0e6', 'sub-pukao-6e11b43e-01', NULL, 'single_choice', '關於跨域治理所包含的核心要素，下列敘述何者錯誤？', '["需以民意為基礎，故應博採眾議，以凝聚共識", "方式多元，涵蓋跨轄區、跨部門、跨政策領域之間的夥伴合作關係", "法制化程度不一，可採行完全法制化的方式，亦可採取任務編組", "應避免引進企業和第三部門的資源，以免因參與者人數過多而引發紛爭"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:31+00:00", "source_pdf_sha1": "911a7b7a5265", "answer_pdf_sha1": "4139af4fbb5e", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "403", "s": "0304", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政學概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
