  ('pukao-6e11b43e-moex-00151', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-113-d1a761c9', 'sub-pukao-6e11b43e-02', NULL, 'single_choice', '法律規定電子遊戲場業之營業場所應距離學校50公尺，但某直轄市自治條例卻規定為800公尺，依 司法院解釋意旨，下列敘述何者正確？', '["該自治條例無效，因違反法律優位原則", "該自治條例無效，因違反法律保留原則", "該自治條例有效，因後法優先於前法", "該自治條例有效，因地方有自治權限"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:31+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "403", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('pukao-6e11b43e-moex-00152', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-113-d1a761c9', 'sub-pukao-6e11b43e-02', NULL, 'single_choice', '下列何者須以法律或法律明確授權之命令為依據始得為之？', '["開放公共空間供街頭藝人展演", "命法定傳染病之確診者居家隔離", "興建橋樑並提供公用", "提供空氣品質預報"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:31+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "403", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('pukao-6e11b43e-moex-00153', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-113-d1a761c9', 'sub-pukao-6e11b43e-02', NULL, 'single_choice', '有關溯及既往與信賴保護原則之敘述，下列何者正確？', '["基於信賴保護原則，法規之適用均不得溯及既往", "真正溯及既往係指新制定之法規，適用於該法規生效前已完結之法律事實", "不真正溯及既往係指新制定之法規，僅適用於該法規生效後發生之法律事實", "不真正溯及既往之法規，不用考量人民對於舊法是否有值得保護之信賴"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:31+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "403", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('pukao-6e11b43e-moex-00154', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-113-d1a761c9', 'sub-pukao-6e11b43e-02', NULL, 'single_choice', '教師及學校之教育或管理措施，即使構成權利之侵害，學生得據以提起行政爭訟請求救濟，但法院及 其他行政爭訟機關應予教師及學校較高之尊重。此屬下列何種概念？', '["行政保留", "裁量餘地", "專業判斷餘地", "法規制定裁量"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:31+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "403", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
  ('pukao-6e11b43e-moex-00155', 'pukao-6e11b43e', 'pukao-6e11b43e-moex-113-d1a761c9', 'sub-pukao-6e11b43e-02', NULL, 'single_choice', '下列何者非屬私經濟行政行為？', '["中央銀行為穩定匯市，購買黃金外幣", "行政機關與得標廠商締結採購契約", "自來水公司提供配水服務", "直轄市政府依自治條例規定，同意相對人利用下水道附掛有線電視纜線並收取使用費"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:31+00:00", "source_pdf_sha1": "6c3edb22667e", "answer_pdf_sha1": "1160bb07cdc1", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "403", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "原住民族行政"}'::jsonb, NULL),
